import { useState, useEffect, useCallback } from 'react'
import { usePlayerContext } from './context'
import type { Bookmark, BookmarkPlugin } from '@tanstack-player/plugin-bookmark'

/**
 * Hook for interacting with the bookmark plugin.
 * Requires the bookmark plugin to be registered on the player.
 *
 * @example
 * ```tsx
 * const { bookmarks, addBookmark, removeBookmark, seekToBookmark } = useBookmarks()
 * ```
 */
export function useBookmarks() {
  const controller = usePlayerContext()
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([])

  const getPlugin = useCallback((): BookmarkPlugin | undefined => {
    return controller.getPlugin<BookmarkPlugin>('bookmark')
  }, [controller])

  // Sync bookmarks on plugin events
  useEffect(() => {
    const refresh = () => {
      const plugin = getPlugin()
      if (plugin) {
        setBookmarks(plugin.getBookmarks())
      }
    }

    // Initial sync
    refresh()

    // Listen for bookmark changes
    const unsub1 = controller.eventBus.on('bookmark:added', refresh)
    const unsub2 = controller.eventBus.on('bookmark:removed', refresh)

    return () => {
      unsub1()
      unsub2()
    }
  }, [controller, getPlugin])

  const addBookmark = useCallback(
    (label?: string, time?: number): Bookmark | undefined => {
      const plugin = getPlugin()
      if (!plugin) {
        console.warn('[TanStack Player] Bookmark plugin is not registered.')
        return
      }
      return plugin.addBookmark(label, time)
    },
    [getPlugin]
  )

  const removeBookmark = useCallback(
    (id: string): boolean => {
      const plugin = getPlugin()
      return plugin?.removeBookmark(id) ?? false
    },
    [getPlugin]
  )

  const seekToBookmark = useCallback(
    (id: string): boolean => {
      const plugin = getPlugin()
      return plugin?.seekToBookmark(id) ?? false
    },
    [getPlugin]
  )

  return {
    bookmarks,
    addBookmark,
    removeBookmark,
    seekToBookmark,
  }
}
