import { useSyncExternalStore, useCallback } from 'react'
import type { PlayerState } from '@tanstack-player/core'
import { usePlayerContext } from './context'

/**
 * Primary hook for controlling the TanStack Player.
 *
 * Returns reactive state + control methods.
 * Must be used inside a <TanStackPlayer /> component.
 *
 * @example
 * ```tsx
 * const { play, pause, isPlaying, currentTime, duration } = useTanStackPlayer()
 * ```
 */
export function useTanStackPlayer() {
  const controller = usePlayerContext()

  // Use useSyncExternalStore for tear-free reads of player state
  const state = useSyncExternalStore(
    useCallback(
      (onStoreChange: () => void) => controller.store.subscribe(onStoreChange),
      [controller]
    ),
    () => controller.store.getState(),
    () => controller.store.getState()
  )

  return {
    // ─── State ────────────────────────────────────
    isPlaying: state.isPlaying,
    isReady: state.isReady,
    duration: state.duration,
    currentTime: state.currentTime,
    buffered: state.buffered,
    volume: state.volume,
    playbackRate: state.playbackRate,
    isFullscreen: state.isFullscreen,
    isMuted: state.isMuted,
    error: state.error,

    // ─── Controls ─────────────────────────────────
    play: () => controller.play(),
    pause: () => controller.pause(),
    seek: (seconds: number) => controller.seek(seconds),
    setVolume: (value: number) => controller.setVolume(value),
    setMuted: (muted: boolean) => controller.setMuted(muted),
    setPlaybackRate: (rate: number) => controller.setPlaybackRate(rate),
    requestFullscreen: () => controller.requestFullscreen(),
    exitFullscreen: () => controller.exitFullscreen(),

    // ─── Direct controller access ─────────────────
    controller,
  }
}
