import React, { useRef, useEffect, useState, useCallback } from 'react'
import { PlayerController, type TanStackPlugin, type PlayerSource } from '@tanstack-player/core'
import { createVideoJsAdapter } from '@tanstack-player/adapter-videojs'
import { TanStackPlayerContext } from './context'

export interface TanStackPlayerProps {
  /** Video source URL or source object(s) */
  src: string | PlayerSource | PlayerSource[]
  /** Auto play on mount */
  autoPlay?: boolean
  /** Show Video.js built-in controls */
  controls?: boolean
  /** Plugins to register */
  plugins?: TanStackPlugin[]
  /** Native Video.js options passthrough */
  videojsOptions?: Record<string, unknown>
  /** Fluid responsive layout */
  fluid?: boolean
  /** Preload strategy */
  preload?: 'auto' | 'metadata' | 'none'
  /** Available playback rates */
  playbackRates?: number[]
  /** CSS class name for the wrapper div */
  className?: string
  /** Inline styles for the wrapper div */
  style?: React.CSSProperties
  /** Children receive PlayerController via context */
  children?: React.ReactNode

  // ─── Event callbacks ──────────────────────────────────
  onReady?: () => void
  onPlay?: () => void
  onPause?: () => void
  onEnded?: () => void
  onError?: (error: Error) => void
  onTimeUpdate?: (currentTime: number, duration: number) => void
}

/**
 * Main TanStack Player React component.
 *
 * Mounts a Video.js player, initializes the core controller,
 * registers plugins, and provides context to hooks.
 *
 * React Strict Mode safe — uses ref tracking to avoid double init.
 */
export function TanStackPlayer({
  src,
  autoPlay = false,
  controls = true,
  plugins,
  videojsOptions,
  fluid = true,
  preload = 'auto',
  playbackRates,
  className,
  style,
  children,
  onReady,
  onPlay,
  onPause,
  onEnded,
  onError,
  onTimeUpdate,
}: TanStackPlayerProps) {
  const containerRef = useRef<HTMLDivElement>(null)
  const controllerRef = useRef<PlayerController | null>(null)
  const initializedRef = useRef(false)
  const [controller, setController] = useState<PlayerController | null>(null)

  // Normalize src to PlayerSource format
  const normalizedSrc = normalizeSrc(src)

  useEffect(() => {
    // Guard for Strict Mode double-mount
    if (initializedRef.current || !containerRef.current) return
    initializedRef.current = true

    const adapter = createVideoJsAdapter()

    const ctrl = new PlayerController({
      adapter,
      src: normalizedSrc,
      autoPlay,
      controls,
      fluid,
      preload,
      playbackRates,
      engineOptions: videojsOptions,
      plugins,
    })

    // Wire up event callbacks
    if (onReady) ctrl.eventBus.on('ready', onReady)
    if (onPlay) ctrl.eventBus.on('play', onPlay)
    if (onPause) ctrl.eventBus.on('pause', onPause)
    if (onEnded) ctrl.eventBus.on('ended', onEnded)
    if (onError) {
      ctrl.eventBus.on('error', (data: any) => onError(data?.error))
    }
    if (onTimeUpdate) {
      ctrl.eventBus.on('timeupdate', (data: any) => {
        onTimeUpdate(data?.currentTime ?? 0, data?.duration ?? 0)
      })
    }

    // Initialize the player in the DOM container
    ctrl.init(containerRef.current)

    controllerRef.current = ctrl
    setController(ctrl)

    return () => {
      ctrl.destroy()
      controllerRef.current = null
      initializedRef.current = false
      setController(null)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  return (
    <TanStackPlayerContext.Provider value={controller}>
      <div
        ref={containerRef}
        className={className}
        style={{ width: '100%', ...style }}
        data-tanstack-player
      />
      {controller && children}
    </TanStackPlayerContext.Provider>
  )
}

// ─── Helpers ──────────────────────────────────────────────

function normalizeSrc(
  src: string | PlayerSource | PlayerSource[]
): PlayerSource | PlayerSource[] {
  if (typeof src === 'string') {
    return { src, type: inferType(src) }
  }
  return src
}

function inferType(src: string): string {
  if (src.endsWith('.m3u8')) return 'application/x-mpegURL'
  if (src.endsWith('.mpd')) return 'application/dash+xml'
  if (src.endsWith('.webm')) return 'video/webm'
  if (src.endsWith('.ogg') || src.endsWith('.ogv')) return 'video/ogg'
  return 'video/mp4'
}
