import React, { createContext, useContext } from 'react'
import type { PlayerController } from '@tanstack-player/core'

/**
 * React context for providing the PlayerController instance
 * to all hooks and child components.
 */
export const TanStackPlayerContext = createContext<PlayerController | null>(null)

/**
 * Internal hook to access the PlayerController from context.
 * Throws if used outside of <TanStackPlayer />.
 */
export function usePlayerContext(): PlayerController {
  const controller = useContext(TanStackPlayerContext)
  if (!controller) {
    throw new Error(
      '[TanStack Player] useTanStackPlayer must be used inside a <TanStackPlayer /> component.'
    )
  }
  return controller
}
